"use strict";(self.webpackChunkalgorithms_way23_ru=self.webpackChunkalgorithms_way23_ru||[]).push([[6630],{4063:(D,B,e)=>{e.r(B),e.d(B,{data:()=>l});const l=JSON.parse('{"key":"v-3eaecd2e","path":"/%D0%B3%D0%BB%D1%83%D1%88%D0%BA%D0%BE%D0%B2%D1%81%D0%BA%D0%B8%D0%B5-%D1%87%D1%82%D0%B5%D0%BD%D0%B8%D1%8F/%D0%B5%D1%80%D0%BE%D0%B2%D0%B5%D0%BD%D0%BA%D0%BE-%D0%BF%D0%BB%D0%B0%D0%BD%D0%BE%D0%B2%D0%B0%D1%8F-%D1%8D%D0%BA%D0%BE%D0%BD%D0%BE%D0%BC%D0%B8%D0%BA%D0%B0-%D0%BA%D0%B0%D0%BA-%D0%BE%D1%81%D0%BD%D0%BE%D0%B2%D0%B0-%D0%B5%D0%B4%D0%B8%D0%BD%D1%81%D1%82%D0%B2%D0%B0-%D1%87%D0%B5%D0%BB%D0%BE%D0%B2%D0%B5%D0%BA%D0%B0-%D0%B8-%D0%BC%D0%B0%D1%88%D0%B8%D0%BD%D1%8B.html","title":"Плановая экономика как основа единства человека и машины","lang":"ru-RU","frontmatter":{},"excerpt":"","headers":[],"git":{"updatedTime":1731092588000},"filePathRelative":"глушковские-чтения/еровенко-плановая-экономика-как-основа-единства-человека-и-машины.md"}')},410:(D,B,e)=>{e.r(B),e.d(B,{default:()=>p});var l=e(6252);const t=(0,l._)("h1",{id:"плановая-экономика-как-основа-единства-человека-и-машины",tabindex:"-1"},[(0,l._)("a",{class:"header-anchor",href:"#плановая-экономика-как-основа-единства-человека-и-машины","aria-hidden":"true"},"#"),(0,l.Uk)(" Плановая экономика как основа единства человека и машины")],-1),a=(0,l._)("p",null,"Еровенко А. М. Перевод с украинского.",-1),r=(0,l._)("p",null,"В наше время идеи планового развития экономики особенно актуальны, ведь современное общество находится на грани перехода к качественно новому способу производства. На смену капитализму должен прийти информационный тип воспроизводства, который носит общественный характер, имеет более высокую производительность, при меньшем использовании ресурсов и освобождает человека для чисто человеческой творческой деятельности от машиноподобного труда.",-1),n=(0,l._)("p",null,"Об этом свидетельствует то, что кризисы происходят все чаще и несут не просто разрушительный характер, уничтожая часть производительных сил, что дает пространство для дальнейшего развития экономики, а и несут угрозы уничтожения человеческой цивилизации с помощью технологий, созданных человеком. В основе современных кризисов лежит несоответствие производственных отношений современным производительным силам. Это противоречие приводит к диспропорциям в экономических процессах и углубляет их стихийный характер, который несет за собой и структурные кризисы, и стихийные перестройки в экономике, и перепроизводство, что не только негативно влияет на экономику, но и не улучшает общественную жизнь.",-1),u=(0,l._)("p",null,"С другой стороны, информационный способ производства все больше проникает во все отрасли и трансформирует их. Появляются новые изобретения, воплощаются в жизнь новые идеи, общество имеет новые потребности и новые пути их удовлетворения. Эра интернета дает всем свободный доступ к информации, наделяя ее новыми качествами.",-1),d=(0,l._)("p",null,"Теперь она своей стоимостью далеко не всегда приумножает состояние крупных капиталистов, а и работает на благо общества, становится средством производства, собственность на которое становится общественной. В свою очередь, распространение информационного способа производства с его научно-техническими революциями, непрерывным развитием высоких технологий и активными изменениями на рынке, которые делают экономику нестабильной и склонной к кризисам и беспорядкам, вызывает логическую заинтересованность в планировании экономики и регулировании её структуры, которое позволит спрогнозировать экономические процессы и сделает человека ключевым субъектом, а не объектом экономического процесса, в руках которого будут рычаги контроля производительных сил и регуляция их направленности на удовлетворение потребностей общества, сознательно управляющего собственным развитием.",-1),i=(0,l._)("p",null,"Переход к плановой экономике, направленной на благо общества, решил бы ряд экономических проблем, но воплощение этой идеи в жизнь требует как минимум социальной основы, коллективизма. В связи с этим идеи целостности экономики как объекта управления, разрабатывавшиеся В. М.Глушковым, как принципиального подхода к управлению являются одними из наиболее перспективных. На этой основе можно будет говорить о неразрывном единстве машины и человека в рамках системного подхода к управлению экономикой.",-1),h={},p=(0,e(3744).Z)(h,[["render",function(D,B){const e=(0,l.up)("RouterLink");return(0,l.wg)(),(0,l.iD)("div",null,[t,a,(0,l._)("p",null,[(0,l.Uk)("Из материалов конференции "),(0,l.Wm)(e,{to:"/%D0%B3%D0%BB%D1%83%D1%88%D0%BA%D0%BE%D0%B2%D1%81%D0%BA%D0%B8%D0%B5-%D1%87%D1%82%D0%B5%D0%BD%D0%B8%D1%8F.html"},{default:(0,l.w5)((()=>[(0,l.Uk)("«Глушковские чтения»")])),_:1}),(0,l.Uk)(" 2014 года.")]),r,n,u,d,i])}]])}}]);